-- Single statement, NO temp table (works with the Supabase editor's pooled connections).
-- Any order; safe to re-run. Needs ts_flight_records to exist.
-- After the last part:  select count(*) from ts_flight_records where id like 'fr_imp_%';
-- Undo all:  delete from ts_flight_records where id like 'fr_imp_%';

insert into ts_flight_records
